  ('judicial-57112235-moex-00188', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於刑法第310條誹謗罪，下列敘述何者錯誤？', '["傳述足以毀損他人名譽之事者，只要能證明傳述之事屬實，均為不罰", "無散布於眾之意圖，而指摘足以毀損他人名譽之事，不構成本罪", "公然潑糞於他人之頭頂，不構成本罪", "純粹以髒話辱罵他人，不構成本罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00189', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲墊起腳尖站在窗外偷窺乙洗澡，關於甲之刑責，下列何者正確？', '["不成立犯罪", "刑法第234條公然猥褻罪", "刑法第315條之1窺視罪", "刑法第225條乘機猥褻罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00190', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於正犯與共犯，下列敘述何者錯誤？', '["依實務見解，共謀共同正犯亦為共同正犯", "教唆犯之處罰從屬於其所教唆之正犯", "甲教唆乙犯罪，乙縱未依教唆內容犯罪，甲仍成立教唆未遂罪", "公務員甲與無公務員身分之配偶乙共同收受賄賂，乙仍以公務員受賄罪之共同正犯論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00191', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲計畫偷取某豪宅保險箱中的鑽石，雖有把握能順利開啟保險箱，但因豪宅警備森嚴，仍怕有所閃失。女 友乙知悉後，提供一把萬能鑰匙給甲，行竊當天，甲使用該萬能鑰匙順利開啟保險箱，取出鑽石後離去。 有關乙之刑責，下列敘述何者正確？', '["成立竊盜未遂罪之幫助犯", "成立竊盜未遂罪之教唆犯", "成立竊盜既遂罪之幫助犯", "成立竊盜既遂罪之間接正犯"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00192', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲在夜市裡欲扒竊皮夾，鎖定一對相談甚歡的乙男與丙女，自後方撞上該乙男，並隨手扒走乙男口袋中的 皮夾。甲越過乙男欲從前方離開現場時，才發現乙男旁邊的丙女是自己的女朋友，一時氣憤暴打乙男之後， 攜帶乙男的錢包離去。下列敘述何者正確？', '["甲犯侵占脫離遺失物罪", "甲犯強盜罪", "甲犯準強盜罪", "甲犯竊盜罪、傷害罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00193', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲為某大學校友會會長兼財務長，校友會章程明訂經費來自於會費繳納與校友捐款，並規定經費應用於在 校學生急難救助、學生獎學金、校友會活動等公益事項。甲因投資失利，將校友會所收會費現金存入自己 帳戶，據為己有。甲應成立何罪？', '["第320條竊盜罪", "第339條詐欺罪", "第336條公益侵占罪", "第337條侵占脫離遺失物罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00194', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '依實務見解，關於賭博罪之敘述，下列何者正確？', '["個人透過網際網路線上參與賭博，亦成立賭博罪", "架設網站供人賭博財物，非屬提供賭博場所", "利用電話傳真機供人聯絡下注，非屬供給賭博場所或聚眾賭博", "當場賭博之器具或財物，限於犯罪行為人所有，始得沒收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
