  ('judicial-57112235-moex-00196', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '關於擄人勒贖罪之敘述，下列何者錯誤？', '["擄人勒贖罪有處罰預備犯之規定", "犯意圖勒贖而擄人之罪，未經取贖而釋放被害人者，應減輕其刑", "犯意圖勒贖而擄人之罪，取贖後而釋放被害人者，得減輕其刑", "犯意圖勒贖而擄人之罪而使人受輕傷者，有加重其刑之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
